class AutocompleteSystem:
    def __init__(self, sentences, times):
        self.trie = {}; self.cur = ""; self.dead = False; self.history = collections.defaultdict(int)
        for s, t in zip(sentences, times): self._add(s, t)
    def _add(self, s, t):
        self.history[s] += t
        node = self.trie
        for c in s:
            if c not in node: node[c] = {}
            node = node[c]
            if '#' not in node: node['#'] = collections.defaultdict(int)
            node['#'][s] += t
    def input(self, c):
        if c == '#': self._add(self.cur, 1); self.cur = ""; return []
        self.cur += c
        node = self.trie
        for char in self.cur:
            if char not in node: return []
            node = node[char]
        res = sorted(node['#'].items(), key=lambda x: (-x[1], x[0]))
        return [x[0] for x in res[:3]]

